export const 鎮宅子孫 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.4) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：桿＋不字平桁＋圈杙垂雙
    線(p => p.M(X(0.9), Z(1.3)).L(X(6.5), Z(1.2)));
    圈(0.6, 1.3);
    圈(6.8, 1.2);
    線(p => p.M(X(1.3), Z(2.5)).L(X(5.9), Z(2.4)), 0.42);
    出(p => p.M(X(3.0), Z(2.5)).C(X(2.6), Z(3.2), X(2.2), Z(3.7), X(1.8), Z(4.1)), 0.36);
    出(p => p.M(X(3.3), Z(2.55)).L(X(3.28), Z(4.4)), 0.36);
    出(p => p.M(X(3.6), Z(2.5)).C(X(4.0), Z(3.2), X(4.4), Z(3.7), X(4.8), Z(4.1)), 0.36);
    圈(2.6, 5.1);
    連([2.6, 5.1], [2.6, 6.3]);
    圈(2.6, 6.3);
    圈(4.4, 5.0);
    連([4.4, 5.0], [4.4, 6.2]);
    圈(4.4, 6.2);
    圈(6.6, 3.5);
    圈(6.7, 5.0);
    // 大匚厂框
    線(p => p.M(X(1.0), Z(7.2)).L(X(1.0), Z(17.6)));
    線(p => p.M(X(1.05), Z(7.25)).L(X(6.7), Z(7.15)));
    線(p => p.M(X(6.7), Z(7.15)).L(X(6.7), Z(17.5)));
    // 內日口箱
    線(p => p.M(X(1.7), Z(8.2)).L(X(1.7), Z(10.4)).L(X(3.6), Z(10.35))
        .L(X(3.6), Z(8.15)).L(X(1.65), Z(8.2)));
    線(p => p.M(X(1.8), Z(9.3)).L(X(3.5), Z(9.27)), 0.32);
    線(p => p.M(X(4.2), Z(8.2)).L(X(4.2), Z(10.3)).L(X(6.1), Z(10.25))
        .L(X(6.1), Z(8.15)).L(X(4.15), Z(8.2)));
    // 田男箱
    線(p => p.M(X(1.8), Z(11.2)).L(X(1.8), Z(13.6)).L(X(4.0), Z(13.55))
        .L(X(4.0), Z(11.15)).L(X(1.75), Z(11.2)));
    線(p => p.M(X(2.9), Z(11.25)).L(X(2.88), Z(13.55)), 0.32);
    線(p => p.M(X(1.9), Z(12.4)).L(X(3.9), Z(12.37)), 0.32);
    出(p => p.M(X(4.6), Z(11.4)).L(X(5.9), Z(11.37)).L(X(5.95), Z(12.5))
        .C(X(5.95), Z(13.0), X(5.6), Z(13.2), X(5.1), Z(13.1)), 0.34);
    線(p => p.M(X(5.25), Z(11.45)).L(X(5.23), Z(12.9)), 0.3);
    // 幺幺幺曲簇
    const 幺 = (cx, cz) => 線(p => p.M(X(cx + 0.4), Z(cz))
        .C(X(cx - 0.3), Z(cz + 0.3), X(cx - 0.3), Z(cz + 0.8), X(cx + 0.2), Z(cz + 0.9))
        .C(X(cx + 0.6), Z(cz + 1.0), X(cx + 0.7), Z(cz + 0.5), X(cx + 0.3), Z(cz + 0.4)), 0.32);
    幺(2.2, 14.4);
    幺(3.3, 14.5);
    幺(4.4, 14.4);
    幺(2.7, 15.7);
    幺(3.8, 15.8);
    幺(4.9, 15.7);
    // 底目
    線(p => p.M(X(1.9), Z(17.0)).L(X(5.9), Z(16.95)), 0.4);
    線(p => p.M(X(1.9), Z(18.0)).L(X(5.9), Z(17.95)), 0.4);
};
